#include <stdio.h>
#include <string.h>
#define MAXLEN 1005
int lcs(const char *a, const char *b) {
    int m = strlen(a), n = strlen(b);
    // Ensure we iterate over the shorter string in the inner loop to save memory
    if (n > m) { // swap to make n <= m
        const char *tmp = a; a = b; b = tmp;
        int t = m; m = n; n = t;
    }
    static int dp[2][MAXLEN];
    int cur = 0, prev = 1;
    for (int i = 0; i <= n; ++i) dp[cur][i] = 0;
    for (int i = 1; i <= m; ++i) {
        prev = cur; cur ^= 1;
        dp[cur][0] = 0;
        for (int j = 1; j <= n; ++j) {
            if (a[i-1] == b[j-1]) dp[cur][j] = dp[prev][j-1] + 1;
            else dp[cur][j] = dp[prev][j] > dp[cur][j-1] ? dp[prev][j] : dp[cur][j-1];
        }
    }
    return dp[cur][n];
}
int main() {
    int T; if (scanf("%d", &T)!=1) return 0; getchar();
    char buf1[MAXLEN], buf2[MAXLEN];
    while (T--) {
        if (!fgets(buf1, MAXLEN, stdin)) break;
        if (!fgets(buf2, MAXLEN, stdin)) break;
        buf1[strcspn(buf1, "\n")] = '\0';
        buf2[strcspn(buf2, "\n")] = '\0';
        printf("%d\n", lcs(buf1, buf2));
    }
    return 0;
}

