#include <bits/stdc++.h>
using namespace std;
int lcs(const string &a, const string &b) {
    int m = a.size(), n = b.size();
    if (n > m) return lcs(b, a);
    vector<int> prev(n+1,0), cur(n+1,0);
    for (int i=1;i<=m;++i){
        for (int j=1;j<=n;++j){
            if (a[i-1]==b[j-1]) cur[j]=prev[j-1]+1;
            else cur[j]=max(prev[j],cur[j-1]);
        }
        swap(prev,cur);
    }
    return prev[n];
}
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0; string s1,s2; getline(cin,s1); // consume endline
    while(T--){
        getline(cin,s1);
        getline(cin,s2);
        cout<<lcs(s1,s2)<<"\n";
    }
    return 0;
}

