import sys

def lcs(a: str, b: str) -> int:
    if len(b) > len(a):
        a, b = b, a
    n = len(b)
    prev = [0] * (n + 1)
    cur = [0] * (n + 1)
    for ch in a:
        for j in range(1, n + 1):
            if ch == b[j-1]:
                cur[j] = prev[j-1] + 1
            else:
                cur[j] = prev[j] if prev[j] > cur[j-1] else cur[j-1]
        prev, cur = cur, prev
    return prev[n]

def main():
    data = sys.stdin.read().splitlines()
    if not data: return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        s1 = data[idx].rstrip('\n')
        s2 = data[idx+1].rstrip('\n')
        idx += 2
        out.append(str(lcs(s1, s2)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

